SELECT count(*) FROM role_type, cast_info, name, aka_name, title, movie_info, char_name WHERE cast_info.role_id = role_type.id AND cast_info.person_id = name.id AND aka_name.person_id = name.id AND cast_info.movie_id = title.id AND movie_info.movie_id = title.id AND cast_info.person_role_id = char_name.id;